
.status-bar {
  width: 100%;
  max-width: 720px;
  background-color: var(--c-surface);
  border: 2px solid var(--c-accent);
  border-radius: 6px;
  font-family: var(--font-body);
  color: var(--c-text);
  font-size: 13px;
  line-height: 1.5;
  margin: 0 auto;
  padding: 10px 14px;
}

.world-row {
  display: flex;
  align-items: baseline;
  gap: 6px;

  .label {
    font-weight: 700;
    color: var(--c-accent-dark);
    min-width: 32px;
  }
  .world-name {
    color: var(--c-primary);
    font-weight: 700;
    font-size: 14px;
  }
  .scene {
    color: var(--c-text-muted);
    font-size: 12px;
  }
}

.divider {
  height: 1px;
  background: var(--c-border);
  margin: 8px 0;
}

.section {
  .section-title {
    font-weight: 700;
    font-size: 12px;
    color: var(--c-accent-dark);
    margin-bottom: 5px;
  }

  .badges-row {
    display: flex;
    flex-wrap: wrap;
    gap: 6px;
    margin-bottom: 4px;
  }

  .badge {
    display: inline-block;
    padding: 2px 10px;
    border-radius: 10px;
    font-size: 12px;
    font-weight: 600;
    color: #fff;
  }

  .badge-safe { background: var(--c-safe); }
  .badge-warn { background: var(--c-warn); }
  .badge-danger { background: var(--c-danger); }
  .badge-info { background: var(--c-info); }
  .badge-muted { background: var(--c-text-muted); }
  .badge-accent { background: var(--c-accent); }

  .kv-line {
    display: flex;
    gap: 6px;
    margin-top: 3px;

    .kv-label {
      min-width: 56px;
      color: var(--c-text-muted);
      font-size: 12px;
    }
    .kv-value {
      color: var(--c-text);
      font-size: 12px;
    }
  }
}

.footprint-list {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.footprint-item {
  display: flex;
  justify-content: space-between;
  font-size: 12px;

  .fp-name {
    color: var(--c-primary);
    font-weight: 600;
  }
  .fp-fame {
    color: var(--c-text-muted);
    font-style: italic;
  }
}
